/* WIKIPEDIA ITALIA: JAVASCRIPT LOGIC */
document.addEventListener('DOMContentLoaded', () => {
    console.log('Wikipedia Engine Initialized');
    const searchInput = document.getElementById('wikiSearch');
    const articles = document.querySelectorAll('.wiki-article');
    const sidebarLinks = document.querySelectorAll('.wiki-sidebar a');

    searchInput.addEventListener('input', (e) => {
        const query = e.target.value.toLowerCase();
        articles.forEach(article => {
            const title = article.querySelector('h2').innerText.toLowerCase();
            const content = article.querySelector('.content-text').innerText.toLowerCase();
            if (title.includes(query) || content.includes(query)) {
                article.classList.remove('hidden');
            } else {
                article.classList.add('hidden');
            }
        });
    });

    sidebarLinks.forEach(link => {
        link.addEventListener('click', (e) => {
            e.preventDefault();
            const targetId = e.target.getAttribute('href').substring(1);
            const targetArticle = document.getElementById(targetId);
            if (targetArticle) {
                targetArticle.scrollIntoView({ behavior: 'smooth' });
            }
        });
    });
});
